#include <stdio.h>
#include <stdbool.h>

/* Logic Gate Functions */
bool NOT(bool a) {
 return !a;
}

bool AND(bool a, bool b) {
 return a && b;
}

bool OR(bool a, bool b) {
 return a || b;
}

bool NAND(bool a, bool b) {
 return !(a && b);
}

bool XNOR(bool a, bool b) {
 return (a == b);
}

/* Design Example 1: Elevator Door Control
 * Boolean Function: O = S AND L
 * Step 3: Derived from truth table (only row 11 gives output 1)
 * Step 5: Implementation with single AND gate
 */
bool elevator_door_control(bool S, bool L) {
 return AND(S, L); // O = S · L
}

/* Design Example 2: 2-Bit Comparator
 * Boolean Function: E = (A1 XNOR B1) AND (A0 XNOR B0)
 * Output is 1 only when both bit pairs are equal
 * Step 5: Implementation with 2 XNOR gates + 1 AND gate
 */
bool two_bit_comparator(bool A1, bool A0, bool B1, bool B0) {
 bool xnor1 = XNOR(A1, B1); // Check if MSB bits match
 bool xnor0 = XNOR(A0, B0); // Check if LSB bits match
 return AND(xnor1, xnor0); // Both must match for equality
}

/* Design Example 3: Majority Vote Circuit
 * Output is 1 if majority (2 or more) of inputs are 1
 * Boolean Function: F = AB + BC + AC
 * Step 4: Minimized using K-map
 */
bool majority_vote(bool A, bool B, bool C) {
 bool ab = AND(A, B); // A AND B
 bool bc = AND(B, C); // B AND C
 bool ac = AND(A, C); // A AND C
 return OR(OR(ab, bc), ac); // AB + BC + AC
}

/* Design Example 4: 2-to-1 Multiplexer
 * Selects between two inputs based on select line
 * Function: Y = S'·D0 + S·D1
 */
bool multiplexer_2to1(bool D0, bool D1, bool S) {
 bool not_s = NOT(S);
 bool term1 = AND(not_s, D0); // S' · D0
 bool term2 = AND(S, D1); // S · D1
 return OR(term1, term2); // Y = S'·D0 + S·D1
}

/* Verification Function - Step 6 of Design Procedure */
void verify_truth_table(int test_case, bool (*func)(), int num_inputs, 
 bool expected[], bool (*get_inputs[])()) {
 printf("Test Case %d: ", test_case);
 bool result = func();
 printf("Result=%d, Expected=%d -> %s\n", 
 result, expected[test_case], 
 result == expected[test_case] ? "PASS" : "FAIL");
}

/* Print truth table header */
void print_header(const char* title, const char* inputs, const char* output) {
 printf("\n========================================\n");
 printf(" %s\n", title);
 printf("========================================\n");
 printf(" %s | %s\n", inputs, output);
 printf("------|-------\n");
}

int main() {
 /* Example 1: Elevator Door Control Verification */
 print_header("Elevator Door Control (O = S · L)", "S L", "O");

 bool S, L;
 for (int i = 0; i < 4; i++) {
 S = (i >> 1) & 1; // Extract bit 1
 L = i & 1; // Extract bit 0
 bool O = elevator_door_control(S, L);
 printf(" %d %d | %d\n", S, L, O);
 }

 /* Example 2: 2-Bit Comparator Verification */
 print_header("2-Bit Comparator (E = (A1⊙B1)·(A0⊙B0))", "A1 A0 B1 B0", "E");

 bool A1, A0, B1, B0;
 for (int i = 0; i < 16; i++) {
 A1 = (i >> 3) & 1;
 A0 = (i >> 2) & 1;
 B1 = (i >> 1) & 1;
 B0 = i & 1;

 bool E = two_bit_comparator(A1, A0, B1, B0);
 bool expected = (A1 == B1) && (A0 == B0);

 printf(" %d %d %d %d | %d %s\n", 
 A1, A0, B1, B0, E, E == expected ? "" : "ERROR");
 }

 /* Example 3: Majority Vote Circuit */
 print_header("Majority Vote (F = AB + BC + AC)", "A B C", "F");

 for (int i = 0; i < 8; i++) {
 A1 = (i >> 2) & 1; // Reusing A1 variable as 'A'
 B1 = (i >> 1) & 1; // Reusing B1 variable as 'B'
 C = i & 1;
 bool F = majority_vote(A1, B1, C);

 // Count ones and determine expected
 int count = A1 + B1 + C;
 bool expected = (count >= 2) ? 1 : 0;

 printf(" %d %d %d | %d %s\n", A1, B1, C, F, F == expected ? "" : "ERROR");
 }

 /* Example 4: 2-to-1 Multiplexer */
 print_header("2-to-1 Multiplexer (Y = S'·D0 + S·D1)", "D0 D1 S", "Y");

 for (int i = 0; i < 4; i++) {
 bool D0 = (i >> 1) & 1;
 bool D1 = i & 1;
 bool S = 0; // First half: S=0 selects D0
 bool Y = multiplexer_2to1(D0, D1, S);
 printf(" %d %d %d | %d\n", D0, D1, S, Y);
 }
 for (int i = 0; i < 4; i++) {
 bool D0 = (i >> 1) & 1;
 bool D1 = i & 1;
 bool S = 1; // Second half: S=1 selects D1
 bool Y = multiplexer_2to1(D0, D1, S);
 printf(" %d %d %d | %d\n", D0, D1, S, Y);
 }

 printf("\n========================================\n");
 printf(" Design Procedure Verification Complete\n");
 printf("========================================\n");

 return 0;
}
